export default function ThreadSection({
                                          title = "Threads",
                                          threads,
                                          isAdmin,
                                          showAddButton = false,
                                          onAddThread,
                                          hoveredId,
                                          setHoveredId,
                                          boxHover,
                                          styles,
                                          width
                                      }) {
    return (
        <div style={{ width, display: "flex", flexDirection: "column" }}>
            {showAddButton && isAdmin && (
                <button style={styles.addBtn} onClick={onAddThread}>
                    Add Thread
                </button>
            )}

            <h3 style={styles.col_title}>{title}</h3>

            <div>
                {(Array.isArray(threads) ? threads : []).map(thread => (
                    <div
                        key={thread.id}
                        style={{
                            ...styles.Threads,
                            ...(hoveredId === `thread-${thread.id}` ? boxHover : {})
                        }}
                        onMouseEnter={() => setHoveredId(`thread-${thread.id}`)}
                        onMouseLeave={() => setHoveredId(null)}
                        onClick={() => {
                            window.location.hash = `#/thread/${thread.id}`;
                        }}
                    >
                        <div style={{ display: "flex", flexDirection: "column" }}>
      <span style={{ fontWeight: 600 }}>
        {thread.title}
      </span>
                            <span style={{ fontSize: "0.75rem", opacity: 0.7 }}>
        {thread.published &&
            new Date(thread.published).toLocaleDateString()}
                                {thread.author && ` · ${thread.author}`}
      </span>
                        </div>
                    </div>
                ))}

            </div>
        </div>
    );
}
